function applyPortalChrome(){const cfg=portalConfig();document.title=cfg.product;document.documentElement.style.setProperty('--accent',cfg.accentColor);document.documentElement.style.setProperty('--cyan',cfg.primaryColor);document.querySelectorAll('.brand strong,.login-brand strong').forEach(el=>el.textContent=cfg.shortName||cfg.brand);document.querySelectorAll('.brand span,.login-brand span').forEach(el=>el.textContent=cfg.product);const logo=document.querySelector('.login-brand .logo');if(logo)logo.textContent=initials(cfg.shortName||cfg.brand).slice(0,1)}
function recordConfigChange(label,value){demoState.actions=demoState.actions||[];demoState.actions.unshift({view:state.view,type:'setting',name:label,value:escapeHtml(value),company:activeClientData().name,actor:actionActor(),createdAt:new Date().toISOString()});demoState.actions=demoState.actions.slice(0,50);storeApi.recordStoreAudit?.('setting-change',activeClientData().name,`${label}: ${value}`,actionActor());saveDemo()}
function formatTimeAgo(iso){const then=new Date(iso).getTime();const diff=Math.max(0,Date.now()-then);const min=Math.floor(diff/60000);if(min<1)return'Just now';if(min<60)return`${min} min ago`;const hrs=Math.floor(min/60);if(hrs<24)return`${hrs} hr ago`;return new Intl.DateTimeFormat('en-US',{month:'short',day:'numeric'}).format(new Date(iso))}
function actionCategory(type){if(/ticket|document/.test(type))return'Service';if(/role|mfa|offboarding/.test(type))return'Privileged';if(/setting|integration|field|api|key/.test(type))return'Configuration';if(/payment|invoice|billing/.test(type))return'Billing';return'Workflow'}
function actionStatus(type){if(/escalation|mfa|offboarding/.test(type))return'warning';if(/close|payment|reply|setting|upload|invite|role-change/.test(type))return'healthy';return'pending'}
function actionIcon(type){if(/ticket|reply|escalation/.test(type))return'?';if(/document/.test(type))return'?';if(/role|mfa|offboarding/.test(type))return'?';if(/payment|billing|invoice/.test(type))return'?';if(/setting|configuration/.test(type))return'?';return'?'}
function actionActor(){return currentProfile().name||state.user?.name||'Portal user'}
function normalizedAuditEvents(){const store=(storeState.audit||[]).map(a=>[actionIcon(a.type),plain(a.type),a.actor||'Portal user',`${a.scope||activeClientData().name} - Shared store`,actionCategory(a.type),formatTimeAgo(a.createdAt),plain(a.details||'Completed'),actionStatus(a.type)]);const live=(demoState.actions||[]).map(a=>[actionIcon(a.type),plain(a.name||a.type),a.actor||actionActor(),`${a.company||activeClientData().name} - ${pageLabel[a.view]||a.view||'Portal'}`,actionCategory(a.type),formatTimeAgo(a.createdAt),plain(a.details||a.value||'Completed'),actionStatus(a.type)]);return[...store,...live,...auditEvents]}
function companyActivity(limit=5,company=activeClientData().name){return normalizedAuditEvents().filter(a=>!company||plain(a[3]).includes(company)||state.role==='msp').slice(0,limit)}
function activityFeed(title='Recent activity',items=companyActivity()){return`<section class="card activity-card"><div class="card-head"><div><h2>${escapeHtml(title)}</h2><p>Actions, workflow changes, and audit events</p></div><button class="btn text" data-view="audit">Audit log ?</button></div><div class="activity-list">${items.length?items.map(a=>`<button class="activity-item" data-action="audit-detail" data-action-label="${escapeHtml(a[1])}"><span class="activity-icon">${a[0]}</span><span><strong>${escapeHtml(a[1])}</strong><small>${escapeHtml(a[2])} - ${escapeHtml(a[3])}</small></span><em class="status ${a[7]}">${escapeHtml(a[5])}</em></button>`).join(''):'<div class="activity-empty">No activity yet. Actions taken in this portal will appear here.</div>'}</div></section>`}
function sourceOfTruth(view=state.view){const mspOwned=new Set(['mspCompany','mspSettings','systemSetup','integrations','automationSettings','identitySettings','notificationSettings','portalSettings','agreementSettings','apiSettings','audit','mspTeam','connectorOverview','callActivity','callerDirectory','dataMapping']);const clientManaged=new Set(['company','team','restrictions','billing','documents','passwords']);const userContributed=new Set(['support','remote','messages','knowledge','services','security','metrics','overview']);if(mspOwned.has(view))return{owner:'MSP Admin Portal',flow:'MSP defaults ? Client Admin overrides ? End User experience',note:'MSP settings are authoritative and inherited by all client portals.'};if(clientManaged.has(view))return{owner:'Client Admin Portal',flow:'MSP defaults ? Client company record ? End User visibility',note:'Client admins manage company-scoped records without changing MSP integrations.'};if(userContributed.has(view))return{owner:'End User Portal',flow:'End User activity ? Client Admin queue ? MSP operations',note:'End-user actions write back to the shared company record and audit trail.'};return{owner:'Shared Portal Record',flow:'MSP ? Client Admin ? End User',note:'This page reads and writes the shared portal data model.'}}
function portalGovernanceBanner(view=state.view){const c=activeClientData();const src=sourceOfTruth(view);return`<div class="governance-banner"><div><span class="ops-kicker">PORTAL DATA CHAIN</span><strong>${escapeHtml(src.owner)} is source for this section</strong><small>${escapeHtml(src.note)}</small></div><div class="governance-flow"><span class="${state.role==='msp'?'active':''}">MSP Admin</span><b>?</b><span class="${state.role==='admin'?'active':''}">Client Admin</span><b>?</b><span class="${state.role==='user'?'active':''}">End User</span></div><em>${escapeHtml(c.name)} - ${escapeHtml(src.flow)}</em></div>`}
function syncCompanyAcrossPortals(company){const record=clientRecords[company?.name];if(!record)return company;const scoped={initials:record.initials,name:record.name,plan:company.plan||record.plan};storeApi.upsertStoreClient?.({name:record.name,initials:record.initials,plan:record.plan,status:parseInt(record.health)<85?'critical':'healthy'});uiState.activeCompany={...(uiState.activeCompany||{}),msp:scoped,admin:scoped,user:scoped};saveJson('northstar-ui-state',uiState);return scoped}
const mspServiceBoards=[['Service Desk','Tier 1 + triage','8 AM - 6 PM local','11 min response','Healthy'],['NOC / Monitoring','Infrastructure alerts','24 x 7 x 365','4 min acknowledgement','Healthy'],['Security Operations','Endpoint and identity incidents','24 x 7 x 365','Immediate for critical','Healthy'],['Projects','Implementations and onboarding','Business hours','2 business days','Review']];
const mspEscalations=[['Priority 1 outage','Service manager + on-call engineer','SMS - Teams - Phone','Immediate'],['Security incident','Security lead + owner','SMS - Teams - Email','Immediate'],['VIP client escalation','Account manager + service manager','Teams - Phone','15 minutes'],['Billing exception','Finance owner','Email - Portal task','1 business day']];
function primaryAction(label){const text=String(label).toLowerCase();if(text.includes('payment'))return'payment';if(/export|csv|statement|report|log/.test(text))return'export';if(text.includes('upload'))return'upload';if(text.includes('invite administrator'))return'invite-admin';if(text.includes('invite'))return'invite';if(text.includes('add client')||text.includes('onboard'))return'add-client';if(text.includes('remote'))return'remote';if(text.includes('article'))return'article-request';if(text.includes('message'))return'create-record';if(text.includes('access')&&state.view==='passwords')return'create-record';if(text.includes('restriction'))return'policy';if(text.includes('change')&&state.view==='company')return'company-change';if(text.includes('refresh')||text.includes('synchronization'))return'refresh';if(text.includes('publish')||text.includes('sync')||text.includes('save'))return'save-settings';if(text.includes('api key'))return'api-key';if(text.includes('integration'))return'integration';if(text.includes('field'))return'field';if(text.includes('workflow')||text.includes('route')||text.includes('template'))return'create-record';if(text.includes('ticket'))return'ticket';return'ticket'}
const head=(k,t,d,a='New support request')=>`<div class="page-head"><div><span class="eyebrow">${k}</span><h1>${t}</h1><p>${d}</p></div><div class="head-actions"><button class="btn secondary" data-view="messages">Message your team</button><button class="btn primary" data-action="${primaryAction(a)}" data-action-label="${escapeHtml(a)}">+ ${escapeHtml(a)}</button></div></div>`;
const stat=(l,v,f,i)=>`<article class="card stat"><div class="stat-top"><span class="stat-label">${l}</span><span class="stat-icon">${i}</span></div><div class="stat-value">${v}</div><div class="stat-foot">${f}</div></article>`;
const row=(icon,title,meta,right)=>`<div class="list-row" data-detail-title="${escapeHtml(plain(title))}" data-detail-meta="${escapeHtml(plain(meta))}"><div class="row-main"><div class="row-icon">${icon}</div><div class="row-copy"><strong>${title}</strong><span>${meta}</span></div></div><div class="row-meta">${right}</div></div>`;
function storeRecordsFor(name){return storeApi.storeRecords?.(name)||storeState.records?.[name]||{}}
function overviewSnapshot(){const c=activeClientData();const records=storeRecordsFor(c.name);const tickets=[...(records.tickets||[]),...(c.tickets||[])];const invoices=[...(records.invoices||[]),...(c.invoices||[])];const docs=[...(records.documents||[]),...(c.documents||[])];const assets=[...(records.assets||[]),...(c.assets||[])];const people=[...(records.people||[]),...(c.people||[])];const renewals=[...(records.renewals||[]),...(c.renewals||[])];const audit=(storeState.audit||[]).filter(a=>a.scope===c.name);const approvals=(storeState.approvals||[]).filter(a=>a.scope===c.name&&a.status==='pending');const open=tickets.filter(t=>!['resolved','paid'].includes(t[4])).length;const due=invoices.find(i=>i[4]&&i[4]!=='paid');const healthyAssets=assets.filter(a=>['healthy','paid'].includes(a[4])).length;const totalAssets=assets.length||1;const attention=assets.filter(a=>!['healthy','paid'].includes(a[4])).length;const healthScore=Math.max(55,Math.round((healthyAssets/totalAssets)*100));const sla=c.metrics?.[0]?.[1]||99;return{c,tickets,invoices,docs,assets,people,renewals,audit,approvals,open,due,attention,healthScore,sla}}
function overview(){const o=overviewSnapshot();const c=o.c;const latestDoc=o.docs[0];const latestAudit=o.audit[0];const nextRenewal=o.renewals[0];const roleAdmin=state.role==='admin';const title=roleAdmin?'CLIENT ADMINISTRATION':'GOOD AFTERNOON';const copy=roleAdmin?`Manage ${c.name} services, people, security, billing, and client-visible records.`:`Here's what's happening across ${c.name} from the shared portal data store.`;const moneyTile=roleAdmin?stat('Amount due',o.due?.[2]||'$0',o.due?`${o.due[0]} - ${o.due[3]}`:'No open balance','?'):stat('SLA response',`${o.sla}%`,c.metrics?.[0]?.[2]||'Measured from support records','?');const supportRows=o.tickets.slice(0,4).map(t=>row('?',t[1],`${t[0]} - ${t[2]}`,`<span class="status ${t[4]}">${t[3]}</span>`)).join('')||'<div class="activity-empty">No tickets yet. New requests will appear here immediately.</div>';const evidence=[['Latest document',latestDoc?`${latestDoc[0]} - ${latestDoc[2]}`:'None published'],['Next renewal',nextRenewal?`${nextRenewal[0]} - ${nextRenewal[1]}`:'No renewal tracked'],['Latest audit event',latestAudit?`${latestAudit.type} - ${formatTimeAgo(latestAudit.createdAt)}`:'No store audit yet'],['Portal users',`${o.people.length} people in company scope`]].map(i=>`<div class="info-row"><span>${escapeHtml(i[0])}</span><strong>${escapeHtml(i[1])}</strong></div>`).join('');const quickRole=roleAdmin?`<button data-view="billing"><span>?</span><strong>Pay invoice</strong><small>${o.due?`${o.due[2]} ${o.due[3]}`:'No balance'}</small></button><button data-view="team"><span>?</span><strong>Manage team</strong><small>${o.people.length} portal users</small></button>`:`<button data-view="knowledge"><span>H</span><strong>Find an answer</strong><small>${o.docs.length} docs indexed</small></button><button data-view="documents"><span>?</span><strong>Documents</strong><small>${latestDoc?latestDoc[2]:'No recent docs'}</small></button>`;return head(title,'Everything, in one place.',copy)+`<div class="grid stats">${stat('Health score',`${o.healthScore}%`,`${o.assets.length} tracked asset categories - ${o.attention} need review`,'?')}${stat('Open requests',String(o.open),o.open?'Tickets from support + workflow records':'No open support items','?')}${moneyTile}${stat('Pending approvals',String(o.approvals.length),o.approvals[0]?.kind||'No pending approvals','?')}</div><div class="grid dashboard"><div class="stack"><section class="card"><div class="card-head"><div><h2>Recent support activity</h2><p>Calculated from ${escapeHtml(c.name)} tickets and workflow records</p></div><button class="btn text" data-view="support">View all ?</button></div><div class="list">${supportRows}</div></section><section class="card"><div class="card-head"><div><h2>Service health</h2><p>Live rollup from asset, endpoint, and security records</p></div><span class="status ${o.healthScore<85?'warning':'healthy'}">${o.healthScore<85?'Attention':'Operational'}</span></div><div class="health-wrap"><div class="ring"><div><strong>${o.healthScore}%</strong><span>STORE SCORE</span></div></div><div class="health-list"><div><span>Asset categories</span><strong>${o.assets.length}</strong></div><div><span>Healthy categories</span><strong>${o.assets.filter(a=>a[4]==='healthy').length}</strong></div><div><span>Documents</span><strong>${o.docs.length}</strong></div><div><span>Audit events</span><strong>${o.audit.length}</strong></div></div></div></section><section class="card"><div class="card-head"><div><h2>Data behind this overview</h2><p>Proof that the tiles are reading actual portal records</p></div></div><div class="info-list">${evidence}</div></section></div><aside class="stack"><section class="card"><div class="card-head"><h2>Quick actions</h2></div><div class="quick"><button data-action="ticket"><span>+</span><strong>Get support</strong><small>${o.open} open now</small></button><button data-view="remote"><span>?</span><strong>Remote help</strong><small>${o.assets.length} asset groups</small></button>${quickRole}</div></section><section class="card announcement"><span class="eyebrow">SHARED STORE</span><h3>${escapeHtml(c.name)} overview is now record-driven</h3><p>Tiles update from tickets, invoices, assets, documents, approvals, and audit events in the portal store.</p><button class="btn text" data-view="${roleAdmin?'company':'documents'}">${roleAdmin?'Review company record':'View records'} ?</button></section></aside></div>`}
function support(){const c=activeClientData();const open=c.tickets.filter(t=>t[4]!=='resolved').length;return head('SUPPORT','How can we help?',`Track ${c.name} requests, reply to technicians, or start something new.`)+`<section class="card"><div class="toolbar"><div class="filters"><button class="filter active">All requests</button><button class="filter">Open ${open}</button><button class="filter">Resolved</button></div><button class="filter">Recently updated ?</button></div><div class="list">${c.tickets.map(t=>row('?',t[1],`${t[0]} - ${t[2]}`,`<span class="status ${t[4]}">${t[3]}</span><span>${t[5]} priority</span>`)).join('')}</div></section><div style="margin-top:16px">${activityFeed('Support activity',companyActivity(5,c.name))}</div>`}
function servicePage(){const c=activeClientData();return head('YOUR TECHNOLOGY','Services & assets',`See what Northstar manages for ${c.name}, how it is performing, and what is included.`,'Request a change')+`<div class="grid stats">${stat('Managed users',String(c.employees),`${Math.max(0,c.agreement.users-c.people.length)} without portal access`,'?')}${stat('Protected devices',String(c.assets.find(a=>a[0]==='Workstations')?.[1]||0),'Policy-backed inventory','?')}${stat('Locations',String(c.agreement.locations),c.location,'?')}${stat('Monthly services',money(c.agreement.monthly),`Agreement renews ${c.agreement.renewal}`,'?')}</div><section class="card"><div class="card-head"><div><h2>Active services</h2><p>Covered by ${escapeHtml(c.agreement.name)}</p></div><span class="status ${parseInt(c.health)<85?'warning':'healthy'}">${parseInt(c.health)<85?'Review needed':'All normal'}</span></div><div class="list">${c.services.map(s=>row(s[2],s[0],s[1],'<span class="status healthy">Active</span><span>View details ?</span>')).join('')}</div></section>`}
function billing(){const c=activeClientData();const due=c.invoices.filter(i=>i[4]!=='paid').reduce((sum,i)=>sum+moneyValue(i[2]),0);const lastPaid=c.invoices.find(i=>i[4]==='paid');const nextRenewal=c.renewals[0];return head('BILLING','Simple, transparent billing.',`Review ${c.name} invoices, payment methods, agreement usage, and upcoming renewals.`,'Make a payment')+`<div class="grid stats">${stat('Amount due',money(due),due?c.invoices.find(i=>i[4]!=='paid')?.[3]:'No open balance','?')}${stat('Last payment',lastPaid?.[2]||'$0',lastPaid?`Paid ${lastPaid[1]}`:'No payment history','?')}${stat('Monthly services',money(c.agreement.monthly),`${c.agreement.name} - ${c.agreement.usedHours}/${c.agreement.includedHours} hrs used`,'?')}${stat('Next renewal',nextRenewal[1],nextRenewal[0],'?')}</div><div class="grid two-col"><section class="card"><div class="card-head"><div><h2>Invoices</h2><p>Payment history and upcoming charges</p></div><button class="btn secondary">Download statement</button></div><div class="table-wrap"><table><thead><tr><th>INVOICE</th><th>DATE</th><th>AMOUNT</th><th>STATUS</th><th></th></tr></thead><tbody>${c.invoices.map(i=>`<tr><td><strong>${i[0]}</strong></td><td>${i[1]}</td><td>${i[2]}</td><td><span class="status ${i[4]}">${i[3]}</span></td><td><a data-action="invoice">View ?</a></td></tr>`).join('')}</tbody></table></div></section><section class="card"><div class="card-head"><div><h2>Agreement usage</h2><p>What the monthly services number is based on</p></div><span class="status healthy">Active</span></div><div class="info-list">${[['Agreement',c.agreement.name],['Term',c.agreement.term],['Covered users',`${c.agreement.users} users`],['Locations',`${c.agreement.locations} offices`],['Support hours',`${c.agreement.usedHours} of ${c.agreement.includedHours} included`],['Monthly recurring',money(c.agreement.monthly)]].map(i=>`<div class="info-row"><span>${i[0]}</span><strong>${i[1]}</strong></div>`).join('')}</div></section></div><div class="grid two-col" style="margin-top:16px"><section class="card"><div class="card-head"><div><h2>Upcoming renewals</h2><p>Items that explain the renewal metric</p></div></div><div class="list">${c.renewals.map(r=>row('?',r[0],`${r[1]} - ${r[2]}`,`<span class="status ${r[4]}">${r[3]}</span>`)).join('')}</div></section><section class="card"><div class="card-head"><div><h2>Payment methods</h2><p>Stored billing contacts and payment rails</p></div><button class="btn text">Add method</button></div><div class="list">${c.payments.map(m=>row('?',m[0],m[1],`<strong>${m[2]}</strong><span class="status ${m[3]}">Verified</span>`)).join('')}</div></section></div>`}
function security(){const c=activeClientData();const endpoint=c.assets.find(a=>a[0]==='Workstations')||['Workstations',0,0];const backup=c.metrics.find(m=>m[0].includes('Backup'))||['Backup success',0,'No backup data'];const patch=c.metrics.find(m=>m[0].includes('Patch'))||['Patch compliance',0,'No patch data'];return head('SECURITY CENTER','Your security, made visible.',`Protection, risks, training, backups, and recommended actions for ${c.name}.`,'Report a concern')+`<div class="grid stats">${stat('Security score',`${parseInt(c.health)} / 100`,parseInt(c.health)<85?'Needs attention':'Strong posture','?')}${stat('MFA coverage','100%',`${c.employees} of ${c.employees} users`,'?')}${stat('Endpoint coverage',`${endpoint[2]} / ${endpoint[1]}`,endpoint[3],'?')}${stat('Backup success',`${backup[1]}%`,backup[2],'?')}</div><div class="grid two-col"><section class="card"><div class="card-head"><div><h2>Protection controls</h2><p>Current company security posture</p></div><span class="status ${parseInt(c.health)<85?'warning':'healthy'}">${parseInt(c.health)<85?'Review':'Enforced'}</span></div><div class="info-list"><div class="info-row"><span>Multifactor authentication</span><strong>100%</strong></div><div class="info-row"><span>Endpoint protection</span><strong>${endpoint[1]} devices</strong></div><div class="info-row"><span>Disk encryption</span><strong>${c.metrics[3][1]}%</strong></div><div class="info-row"><span>Patch compliance</span><strong>${patch[1]}%</strong></div><div class="info-row"><span>Open incidents</span><strong>${c.findings.filter(f=>['critical','warning'].includes(f[3])).length}</strong></div></div></section><section class="card"><div class="card-head"><div><h2>Recommended actions</h2><p>Small steps that reduce risk</p></div></div><div class="list">${c.findings.slice(0,3).map(f=>row('!',f[0],`${f[1]} - ${f[2]}`,`<span class="status ${f[3]}">Review</span>`)).join('')}</div></section></div>`}
function metrics(){const c=activeClientData();const open=c.tickets.filter(t=>!['resolved','paid'].includes(t[4])).length;return head('SERVICE ANALYTICS','Metrics that make service accountable.',`Operational, support, security, and satisfaction performance for ${c.name}.`,'Export report')+`<div class="grid stats">${stat('SLA attainment',`${c.metrics[0][1]}%`,c.metrics[0][2],'?')}${stat('Open requests',String(open),`${open} open requests in queue`,'?')}${stat('First-contact',`${c.metrics[1][1]}%`,c.metrics[1][2],'?')}${stat('Health score',c.health,'Client service score','?')}</div><div class="grid two-col"><section class="card stat"><div class="card-head"><div><h2>Service desk performance</h2><p>Each score ties to ticket activity</p></div></div>${c.metrics.slice(0,3).map(m=>`<div class="metric-label"><span>${m[0]}</span><strong>${m[1]}%</strong></div><div class="progress-track"><div class="progress-fill" style="width:${m[1]}%"></div></div><p class="metric-note">${m[2]}</p>`).join('')}</section><section class="card stat"><div class="card-head"><div><h2>Technology performance</h2><p>Backed by service and asset records</p></div></div>${c.metrics.slice(3).map(m=>`<div class="metric-label"><span>${m[0]}</span><strong>${m[1]}%</strong></div><div class="progress-track"><div class="progress-fill" style="width:${m[1]}%"></div></div><p class="metric-note">${m[2]}</p>`).join('')}</section></div><section class="card" style="margin-top:16px"><div class="card-head"><div><h2>Metric evidence</h2><p>Rows feeding the summary tiles</p></div></div><div class="table-wrap"><table><thead><tr><th>METRIC</th><th>SOURCE</th><th>PERIOD</th><th>VALUE</th></tr></thead><tbody>${c.metrics.map(m=>`<tr><td><strong>${m[0]}</strong></td><td>${m[2]}</td><td>Last 30 days</td><td>${m[1]}%</td></tr>`).join('')}</tbody></table></div></section>`}
function remote(){const c=activeClientData();const deviceCount=c.assets.find(a=>a[0]==='Workstations')?.[1]||0;return head('REMOTE SUPPORT','Remote help, on your terms.',`Authorize Northstar to securely connect to enrolled ${c.name} devices.`,'Request remote support')+`<div class="grid stats">${stat('Managed devices',String(deviceCount),`${Math.max(0,deviceCount-3)} online now`,'?')}${stat('Active sessions','0','No one connected','?')}${stat('SLA response',`${c.metrics[0][1]}%`,c.metrics[0][2],'?')}${stat('Consent policy','Required','Every workstation','?')}</div><section class="card"><div class="card-head"><div><h2>${escapeHtml(c.name)} devices</h2><p>Only devices assigned to this company are shown</p></div><span class="status healthy">Consent enforced</span></div><div class="list">${[[`${c.initials}-LT-042`,'Executive laptop','Online'],[`${c.initials}-WS-019`,'Office workstation','Online'],[`${c.initials}-CR-002`,'Conference room PC',parseInt(c.health)<85?'Attention':'Offline']].map(d=>row('?',d[1],`${d[0]} - Windows 11 Pro`,`<span class="status ${d[2]==='Online'?'healthy':'warning'}">${d[2]}</span><button class="btn text" data-action="remote">Request help</button>`)).join('')}</div></section>`}
function knowledge(){return head('KNOWLEDGE BASE','Answers without the wait.','Client-approved guides and processes published by your MSP.','Request an article')+`<div class="grid stats">${stat('Published guides','28','5 updated this month','?')}${stat('Processes','14','All currently reviewed','?')}${stat('Popular topic','Microsoft 365','12 views this week','?')}${stat('Average rating','4.8 / 5','Helpful content','?')}</div><section class="card"><div class="card-head"><div><h2>Popular knowledge</h2><p>Documentation available to your account</p></div></div><div class="list">${[['New employee onboarding','Process - Updated yesterday'],['Connect to the company VPN','How-to - Updated Jul 8'],['Conference room quick start','How-to - Updated Jul 3'],['Business continuity contacts','Critical - Reviewed Jun 28'],['Approved software catalog','Reference - Updated Jun 20']].map(a=>row('?',a[0],a[1],'<button class="btn text" data-action="article">Open ?</button>')).join('')}</div></section>`}
function messages(){return head('MESSAGES','Stay connected.','Conversation with your account, support, and billing teams.','New message')+`<section class="card"><div class="list">${[['MJ','Maya Johnson','Your Q3 business review is ready. I highlighted three recommendations.','Today, 10:24 AM'],['RL','Ryan Lee','The firewall update is complete. Everything is healthy.','Yesterday'],['NB','Northstar Billing','Invoice INV-2026-0711 is now available.','Jul 1']].map(m=>row(m[0],m[1],m[2],`<strong>${m[3]}</strong><span>Open ?</span>`)).join('')}</div></section>`}
function documents(){const c=activeClientData();return head('DOCUMENT LIBRARY','Everything important, organized.',`${c.name} agreements, reports, plans, invoices, and shared resources.`,'Upload document')+`<section class="card"><div class="toolbar"><div class="filters"><button class="filter active">All files</button><button class="filter">Reports</button><button class="filter">Agreements</button><button class="filter">Plans</button></div><button class="filter">Newest first ?</button></div><div class="list">${c.documents.map(d=>row('?',d[0],`${d[3]} - ${d[1]}`,`<strong>${d[2]}</strong><button class="btn text" data-action="download" data-download-title="${escapeHtml(d[0])}">Download ?</button>`)).join('')}</div></section>`}
function passwords(){return head('SECURE PASSWORDS','Shared access, without shared risk.','Approved credentials with MFA, permissions, and audit history.','Request access')+`<div class="admin-banner"><strong>? Protected administrator area</strong><span>Every password reveal requires verification and is recorded in the audit log.</span></div><div class="grid stats">${stat('Shared credentials','18','5 visible to your role','?')}${stat('MFA protected','100%','Step-up verification','?')}${stat('Access reviews','Current','Next review Oct 1','?')}${stat('Recent reveals','2','Last 30 days','?')}</div><section class="card"><div class="card-head"><div><h2>Credential vault</h2><p>Secrets approved for company administrators</p></div></div><div class="list">${[['Microsoft 365 break-glass account','Microsoft 365'],['Domain registrar - primary','Cloudflare'],['ISP account - Boston office','Verizon Business'],['Alarm panel administration','Facilities']].map(s=>row('?',s[0],s[1],'<strong>------------</strong><button class="btn text" data-action="reveal">Verify & reveal</button>')).join('')}</div></section>`}
function company(){const c=activeClientData();const primary=c.people[0]||['','Primary contact','not-set@example.com'];const billing=c.people.find(p=>String(p[3]).toLowerCase().includes('billing'))||c.people[1]||primary;return head('COMPANY PROFILE','Your business data, kept current.',`The ${c.name} master client record used across support, billing, and security.`,'Request a change')+`<div class="grid two-col"><section class="card"><div class="card-head"><div><h2>Organization</h2><p>Verified company record</p></div><span class="status healthy">Verified</span></div><div class="info-list">${[['Legal name',`${c.name}, Inc.`],['Primary location',c.address],['Main phone',c.phone],['Website',c.website],['Industry',c.industry],['Employees',String(c.employees)]].map(i=>`<div class="info-row"><span>${i[0]}</span><strong>${i[1]}</strong></div>`).join('')}</div></section><section class="card"><div class="card-head"><div><h2>Service profile</h2><p>Operational and escalation details</p></div></div><div class="info-list">${[['Primary contact',primary[1]],['Billing contact',billing[1]],['Executive contact',primary[1]],['Support hours','24 - 7 - 365'],['Agreement',c.agreement.name],['Renewal',c.agreement.renewal]].map(i=>`<div class="info-row"><span>${i[0]}</span><strong>${i[1]}</strong></div>`).join('')}</div></section></div>`}
function restrictions(){const c=activeClientData();const rules=[['Require MFA for portal users','Every login requires a second factor',true],['Restrict password vault by IP','Reveals limited to approved networks',true],['Require remote-session approval','Users approve every connection',true],['Limit downloads to managed devices','Files require a compliant endpoint',parseInt(c.health)<85],['Notify admins of privileged activity','Alert after reveals or role changes',true]];return head('ACCESS GOVERNANCE','Control who can do what, where, and when.',`Conditional access, allowlists, approvals, and privileged controls for ${c.name}.`,'Create restriction')+`<div class="admin-banner"><strong>? Client administrator only</strong><span>Policies apply only to ${escapeHtml(c.name)}. Integration credentials remain controlled by Northstar.</span></div><div class="grid stats">${stat('Active policies',String(rules.filter(r=>r[2]).length),'company-specific controls','?')}${stat('Approved networks',String(c.agreement.locations+1),`${c.location} - MSP VPN`,'?')}${stat('Blocked attempts',String(c.findings.find(f=>f[0]==='Conditional access')?.[1]||'0'),'Last 30 days','?')}${stat('Coverage','100%',`${c.people.length} portal users`,'?')}</div><div class="grid two-col"><section class="card"><div class="card-head"><div><h2>Access policies</h2><p>Controls enforced across this account</p></div></div><div class="list">${rules.map(r=>`<div class="policy"><div class="policy-head"><div><h3>${r[0]}</h3><p>${r[1]}</p></div><button class="toggle ${r[2]?'on':''}" data-action="toggle" aria-label="Toggle policy"></button></div></div>`).join('')}</div></section><section class="card"><div class="card-head"><div><h2>Network allowlist</h2><p>Trusted source networks</p></div><button class="btn text">Add</button></div><div class="info-list">${[[`${c.location} office`,'198.51.100.0/28'],['Remote workforce VPN','192.0.2.128/27'],['Northstar VPN','203.0.113.64/29']].map(i=>`<div class="info-row"><span>${i[0]}</span><strong>${i[1]}</strong></div>`).join('')}</div></section></div>`}
function team(){const c=activeClientData();const admins=c.people.filter(p=>String(p[3]).toLowerCase().includes('admin')).length;const pending=parseInt(c.health)<85?2:1;return head('PEOPLE & ACCESS','Your team, your control.',`Manage ${c.name} users, roles, departments, MFA, approvals, and onboarding status.`,'Invite person')+`<div class="grid stats">${stat('Portal users',String(c.people.length),`${admins} administrators`,'?')}${stat('Managed employees',String(c.employees),`${c.people.length} with portal access`,'?')}${stat('Pending invites',String(pending),pending>1?'Multiple invites require review':'Invite expires in 4 days','?')}${stat('MFA enrolled','100%',`${c.people.length} of ${c.people.length} portal users`,'?')}</div><div class="grid two-col"><section class="card"><div class="card-head"><div><h2>Portal access</h2><p>People who can view or manage this account</p></div><button class="btn secondary">Manage roles</button></div><div class="table-wrap"><table><thead><tr><th>PERSON</th><th>ROLE</th><th>DEPARTMENT</th><th>PHONE</th><th>MFA</th><th>LAST LOGIN</th></tr></thead><tbody>${c.people.map((p,i)=>{const dept=p[4]||['IT Leadership','Finance','Operations','Facilities'][i%4];const phone=p[5]||['(617) 555-0142','(617) 555-0184','(617) 555-0133','(617) 555-0168'][i%4];return`<tr><td><div class="client-table-avatar"><div class="client-logo">${p[0]}</div><div><strong>${p[1]}</strong><small>${p[2]}</small></div></div></td><td>${p[3]}</td><td>${dept}</td><td>${phone}</td><td><span class="status healthy">Enrolled</span></td><td>${['Today, 8:42 AM','Yesterday','Jul 10','Jul 8'][i%4]}</td></tr>`}).join('')}</tbody></table></div></section><section class="card"><div class="card-head"><div><h2>Access controls</h2><p>Governance attached to the people list</p></div></div><div class="info-list">${[['Default role','Member'],['Admin approval','Required for billing, passwords, and restrictions'],['Offboarding workflow','Disable portal, revoke sessions, preserve mailbox'],['Manager approval','Required for access changes'],['Invite expiration','7 days'],['Audit coverage','Role, MFA, password reveal, and document downloads']].map(i=>`<div class="info-row"><span>${i[0]}</span><strong>${i[1]}</strong></div>`).join('')}</div></section></div><div style="margin-top:16px">${activityFeed('Access activity',companyActivity(5,c.name))}</div>`}
const clientPortfolio=[...(demoState.clients||[]),['AC','Acme & Co.','42 users - Boston, MA','Healthy','healthy','$4,120'],['BL','Brightline Legal','68 users - New York, NY','Attention','warning','$7,850'],['HC','Harbor Construction','115 users - Providence, RI','Healthy','healthy','$11,420'],['NS','Northshore Dental','31 users - Salem, MA','Healthy','healthy','$3,680'],['AP','Atlas Partners','86 users - Hartford, CT','At risk','critical','$9,240'],['GF','Greenfield Foods','154 users - Worcester, MA','Healthy','healthy','$14,780']].filter((row,index,items)=>items.findIndex(item=>item[1]===row[1])===index);
function management(){return head('MSP COMMAND CENTER','Your entire client portfolio, at a glance.','Service delivery, risk, revenue, and client experience across every managed account.','Add client')+`<div class="grid stats">${stat('Managed clients','24','<span class="positive">+2</span> this quarter','?')}${stat('Monthly recurring','$186,420','<span class="positive">+6.8%</span> year over year','?')}${stat('Managed users','1,284','Across 31 locations','?')}${stat('SLA attainment','98.7%','Target: 98%','?')}</div><div class="portfolio-grid"><div class="stack"><section class="card"><div class="card-head"><div><h2>Client health</h2><p>Accounts requiring attention first</p></div><button class="btn text" data-view="clients">View all clients ?</button></div><div class="list">${clientPortfolio.slice(0,5).map(c=>row(c[0],c[1],c[2],`<span class="status ${c[4]}">${c[3]}</span><span>${c[5]} MRR</span>`)).join('')}</div></section><section class="card"><div class="card-head"><div><h2>Service desk pulse</h2><p>Ticket flow across all service boards</p></div><button class="btn text" data-view="serviceDesk">Open command queue ?</button></div><div class="table-wrap"><table><thead><tr><th>CLIENT</th><th>OPEN</th><th>WAITING</th><th>AVG RESPONSE</th><th>SLA</th></tr></thead><tbody>${[['Brightline Legal',8,3,'14 min','97.2%'],['Atlas Partners',11,2,'18 min','94.8%'],['Acme & Co.',2,1,'11 min','99.4%'],['Harbor Construction',5,0,'9 min','100%']].map(r=>`<tr><td><strong>${r[0]}</strong></td><td>${r[1]}</td><td>${r[2]}</td><td>${r[3]}</td><td><span class="status ${parseFloat(r[4])<98?'warning':'healthy'}">${r[4]}</span></td></tr>`).join('')}</tbody></table></div></section></div><aside class="stack"><section class="card management-callout"><span class="eyebrow">TODAY'S PRIORITY</span><h3>Atlas Partners needs executive attention</h3><p>Security score dropped 12 points and three critical devices remain unpatched.</p><button class="btn text" data-view="clients">Open client record ?</button></section><section class="card"><div class="card-head"><div><h2>MRR trend</h2><p>Last six months</p></div><strong>$186.4k</strong></div><div style="padding:0 20px 24px"><div class="trend">${[58,63,68,72,77,84].map((v,i)=>`<div class="trend-col"><div class="trend-bar ${i===5?'active':''}" style="height:${v}%"></div><span>${['Feb','Mar','Apr','May','Jun','Jul'][i]}</span></div>`).join('')}</div></div></section><section class="card"><div class="card-head"><div><h2>Platform status</h2><p>Integration and synchronization health</p></div></div><div class="info-list">${[['ConnectWise PSA','Operational'],['ScreenConnect','Operational'],['Hudu','Operational'],['Bitdefender','1 delayed sync'],['Microsoft 365','Operational']].map(i=>`<div class="info-row"><span>${i[0]}</span><strong class="${i[1].includes('delayed')?'risk-medium':''}">${i[1]}</strong></div>`).join('')}</div></section></aside></div>`}
function mspCompany(){const cfg=portalConfig();return head('MSP COMPANY','Configure your MSP organization.','Branding, service identity, operating hours, service boards, escalation defaults, billing identity, and client-facing presentation.','Save settings')+`<div class="grid stats">${stat('Operating brand',cfg.brand,'Used on client portals','?')}${stat('Support coverage','24 x 7',`${cfg.supportPhone} - ${cfg.supportEmail}`,'?')}${stat('Service boards',String(mspServiceBoards.length),'Desk, NOC, security, projects','?')}${stat('Portal product',cfg.product,cfg.domain,'?')}</div><div class="grid two-col">${settingsCard('MSP IDENTITY','Company profile',`<div class="settings-form-grid"><label>Legal company name<input value="${escapeHtml(settingValue('mspCompany','Legal company name','Example MSP, LLC'))}"></label><label>Operating brand<input value="${escapeHtml(cfg.brand)}"></label><label>Main office<input value="${escapeHtml(settingValue('mspCompany','Main office','Simi Valley, CA'))}"></label><label>Primary domain<input value="${escapeHtml(settingValue('mspCompany','Primary domain','msp.example'))}"></label><label>Support email<input value="${escapeHtml(cfg.supportEmail)}"></label><label>Support phone<input value="${escapeHtml(cfg.supportPhone)}"></label><label>Billing email<input value="${escapeHtml(settingValue('mspCompany','Billing email','billing@msp.example'))}"></label><label>Client portal domain<input value="${escapeHtml(cfg.domain)}"></label></div>`)}${settingsCard('BRAND PRESENTATION','Client-facing identity',`<div class="settings-form-grid"><label>Portal product name<input value="${escapeHtml(cfg.product)}"></label><label>Short company name<input value="${escapeHtml(cfg.shortName)}"></label><label>Primary brand color<input value="${escapeHtml(cfg.primaryColor)}"></label><label>Accent color<input value="${escapeHtml(cfg.accentColor)}"></label><label>Default sender name<input value="${escapeHtml(cfg.sender)}"></label><label>Client footer text<input value="${escapeHtml(cfg.footer)}"></label><label>Logo mode<select><option>Northstar mark</option><option>Example MSP wordmark</option><option>Client co-branding</option></select></label><label>Maintenance banner style<select><option>Operational tone</option><option>Executive tone</option><option>Technical tone</option></select></label></div>`)}</div><div class="grid two-col">${settingsCard('OPERATING MODEL','Service defaults',`<div class="settings-form-grid"><label>Business hours<input value="${escapeHtml(settingValue('mspCompany','Business hours','Monday-Friday, 8:00 AM-6:00 PM local'))}"></label><label>After-hours coverage<select><option>Critical incidents only</option><option>All support requests</option><option>Security and infrastructure only</option></select></label><label>Default SLA target<select><option>Priority based SLA matrix</option><option>15 minute response for all tickets</option></select></label><label>Client time zone policy<select><option>Use each client company time zone</option><option>Use MSP headquarters time zone</option></select></label><label>Default ticket board<select><option>Service Desk</option><option>NOC / Monitoring</option><option>Projects</option></select></label><label>Default account owner<select><option>Maya Johnson</option><option>Chris Hall</option><option>Ryan Scott</option></select></label></div>`)}${settingsCard('CLIENT EXPERIENCE DEFAULTS','What clients see',settingToggle('Show MSP company identity','Display MSP name, support phone, support email, and portal footer')+settingToggle('Show live service status','Expose approved service health and maintenance events')+settingToggle('Allow client logo co-branding','Let selected companies show their logo beside the MSP brand')+settingToggle('Publish business review prompts','Show QBR, roadmap, lifecycle, and renewal reminders')+settingToggle('Require MSP approval for client profile edits','Hold company data changes for internal review'))}</div><div class="grid two-col">${settingsCard('SERVICE BOARDS','Internal ownership',`<div class="table-wrap"><table><thead><tr><th>BOARD</th><th>OWNER</th><th>COVERAGE</th><th>SLA</th><th>STATE</th></tr></thead><tbody>${mspServiceBoards.map(b=>`<tr><td><strong>${b[0]}</strong></td><td>${b[1]}</td><td>${b[2]}</td><td>${b[3]}</td><td><span class="status ${b[4]==='Healthy'?'healthy':'warning'}">${b[4]}</span></td></tr>`).join('')}</tbody></table></div>`,`<button class="btn secondary" data-action="create-record" data-action-label="New service board">New board</button>`)}${settingsCard('ESCALATION MATRIX','Who gets notified',`<div class="table-wrap"><table><thead><tr><th>TRIGGER</th><th>OWNER</th><th>CHANNELS</th><th>TARGET</th></tr></thead><tbody>${mspEscalations.map(e=>`<tr><td><strong>${e[0]}</strong></td><td>${e[1]}</td><td>${e[2]}</td><td>${e[3]}</td></tr>`).join('')}</tbody></table></div>`,`<button class="btn secondary" data-action="create-record" data-action-label="New escalation path">New path</button>`)}</div><div class="grid two-col">${settingsCard('COMPLIANCE & LEGAL','Business controls',settingToggle('Require audit notes for privileged changes','Prompt operators for business justification on sensitive actions')+settingToggle('Expose data-processing notice','Show privacy and data-processing language in client portals')+settingToggle('Enforce company-scoped exports','Prevent cross-client exports unless MSP owner approves')+settingToggle('Monthly internal access review','Generate MSP operator, API key, and integration access review tasks'))}${settingsCard('BILLING IDENTITY','Commercial defaults',`<div class="settings-form-grid"><label>Invoice remittance name<input value="${escapeHtml(settingValue('mspCompany','Invoice remittance name','Example MSP, LLC'))}"></label><label>Default payment terms<select><option>Net 15</option><option>Due on receipt</option><option>Net 30</option></select></label><label>Tax region<input value="${escapeHtml(settingValue('mspCompany','Tax region','California'))}"></label><label>Billing contact<input value="${escapeHtml(settingValue('mspCompany','Billing contact','billing@msp.example'))}"></label><label>Renewal owner<select><option>Account manager</option><option>Finance owner</option><option>Service manager</option></select></label><label>Default uplift<input value="${escapeHtml(settingValue('mspCompany','Default uplift','5.0%'))}"></label></div>`)}</div>`}
function clients(){return head('MULTI-CLIENT MANAGEMENT','Clients','Search, prioritize, and manage every client organization from one place.','Onboard client')+`<div class="grid stats">${stat('Active clients','24','All agreement types','?')}${stat('Healthy','21','87.5% of portfolio','?')}${stat('Needs attention','2','Operational follow-up','!')}${stat('At risk','1','Executive escalation','?')}</div><section class="card"><div class="toolbar"><div class="management-filter"><button class="filter active">All clients 24</button><button class="filter">Healthy 21</button><button class="filter">Attention 2</button><button class="filter">At risk 1</button></div><button class="filter">Sort: Health priority ?</button></div><div class="table-wrap"><table><thead><tr><th>CLIENT</th><th>HEALTH</th><th>USERS</th><th>OPEN TICKETS</th><th>SECURITY</th><th>MRR</th><th>ACCOUNT OWNER</th></tr></thead><tbody>${clientPortfolio.map((c,i)=>`<tr><td><div class="client-table-avatar"><div class="client-logo">${c[0]}</div><div><strong>${c[1]}</strong><small>${c[2].split(' - ')[1]}</small></div></div></td><td><span class="status ${c[4]}">${c[3]}</span></td><td>${c[2].split(' ')[0]}</td><td>${[2,8,5,1,11,4][i]}</td><td>${[94,88,97,96,76,92][i]}/100</td><td>${c[5]}</td><td>${['Maya Johnson','Chris Hall','Maya Johnson','Ryan Scott','Chris Hall','Maya Johnson'][i]}</td></tr>`).join('')}</tbody></table></div></section>`}
function serviceDesk(){return head('CROSS-CLIENT SERVICE DESK','Command queue','Prioritize incidents, SLA risk, and client communications across all service boards.','Create ticket')+`<div class="grid stats">${stat('Open tickets','37','Across 18 clients','?')}${stat('Critical','3','Immediate attention','!')}${stat('SLA at risk','5','Due within 30 minutes','?')}${stat('Waiting on client','12','Automations active','?')}</div><section class="card"><div class="toolbar"><div class="management-filter"><button class="filter active">Priority queue</button><button class="filter">Critical 3</button><button class="filter">SLA risk 5</button><button class="filter">Unassigned 4</button></div><button class="filter">All service boards ?</button></div><div class="list">${[['!','Atlas Partners - AP-8931','Suspected account compromise - executive user','Critical - 4 min remaining','critical'],['!','Brightline Legal - BL-4412','Document management unavailable','High - 18 min remaining','warning'],['?','Harbor Construction - HC-2188','New site onboarding questions','Normal - 32 min remaining','progress'],['?','Acme & Co. - NS-2841','VPN connection drops intermittently','High - In progress','progress'],['?','Greenfield Foods - GF-9917','Warehouse printer deployment','Normal - Scheduled','pending']].map(t=>row(t[0],t[1],t[2],`<span class="status ${t[4]}">${t[3]}</span><span>Open ticket ?</span>`)).join('')}</div></section>`}
function operations(){return head('FLEET OPERATIONS','Operational control','Device compliance, security posture, backups, patching, and service health across clients.','Export operations report')+`<div class="grid stats">${stat('Managed endpoints','1,486','98.2% online','?')}${stat('Patch compliance','96.4%','53 need attention','?')}${stat('Protected devices','99.1%','13 agent issues','?')}${stat('Backup success','99.7%','7 jobs require review','?')}</div><div class="grid two-col"><section class="card stat"><div class="card-head"><div><h2>Portfolio compliance</h2><p>Weighted across managed endpoints</p></div></div>${[['Endpoint protection',99.1],['Disk encryption',97.8],['Patch compliance',96.4],['Backup success',99.7],['MFA coverage',98.9]].map(m=>`<div class="metric-label"><span>${m[0]}</span><strong>${m[1]}%</strong></div><div class="progress-track"><div class="progress-fill" style="width:${m[1]}%"></div></div>`).join('')}</section><section class="card"><div class="card-head"><div><h2>Exceptions by client</h2><p>Highest operational risk first</p></div></div><div class="list">${[['AP','Atlas Partners','3 critical patches - 2 AV agents','critical'],['BL','Brightline Legal','6 backup warnings','warning'],['GF','Greenfield Foods','8 devices pending restart','pending'],['AC','Acme & Co.','1 aging workstation','pending']].map(x=>row(x[0],x[1],x[2],`<span class="status ${x[3]}">${x[3]==='critical'?'Critical':'Review'}</span>`)).join('')}</div></section></div>`}
function revenue(){const mrr=clientPortfolio.reduce((sum,c)=>sum+moneyValue(c[5]),0);const renewalArr=312000;return head('REVENUE & AGREEMENTS','Commercial overview','Recurring revenue, agreement health, renewals, billing exceptions, and service profitability.','Export financial report')+`<div class="grid stats">${stat('Monthly recurring',money(mrr),'Visible portfolio rows','?')}${stat('Annualized revenue',money(mrr*12),'MRR - 12','?')}${stat('Renewals due','4',`${money(renewalArr)} ARR in 90 days`,'?')}${stat('Past due','$12,840','3 client accounts','!')}</div><div class="grid two-col"><section class="card"><div class="card-head"><div><h2>Upcoming renewals</h2><p>Next 90 days</p></div></div><div class="list">${[['AP','Atlas Partners','Aug 14 - $110,880 ARR'],['BL','Brightline Legal','Sep 1 - $94,200 ARR'],['NS','Northshore Dental','Sep 18 - $44,160 ARR'],['AC','Acme & Co.','Oct 1 - $62,760 ARR']].map(r=>row(r[0],r[1],r[2],'<button class="btn text">Review ?</button>')).join('')}</div></section><section class="card"><div class="card-head"><div><h2>Agreement mix</h2><p>Monthly recurring revenue</p></div></div><div class="info-list">${[['Managed Complete','$112,400 - 60%'],['Managed Essentials','$43,280 - 23%'],['Security Managed','$18,920 - 10%'],['Cloud & Voice','$11,820 - 7%']].map(i=>`<div class="info-row"><span>${i[0]}</span><strong>${i[1]}</strong></div>`).join('')}</div></section></div>`}
function audit(){const events=normalizedAuditEvents();const privileged=events.filter(a=>a[4]==='Privileged').length;const denied=events.filter(a=>a[1].toLowerCase().includes('blocked')).length;return head('AUDIT & GOVERNANCE','Audit activity','Privileged actions, client access, integration changes, and security events across the platform.','Export audit log')+`<div class="grid stats">${stat('Events shown',String(events.length),'Live + seeded audit rows','?')}${stat('Privileged actions',String(privileged),'Credential and role events','?')}${stat('Denied attempts',String(denied),'Automatically blocked','?')}${stat('Open reviews',String(events.filter(a=>a[7]==='warning'||a[7]==='pending').length),'Require review','?')}</div><section class="card"><div class="toolbar"><div class="management-filter"><button class="filter active">All activity</button><button class="filter">Privileged</button><button class="filter">Security</button><button class="filter">Configuration</button><button class="filter">Billing</button></div><button class="filter">Today ?</button></div><div class="table-wrap"><table><thead><tr><th>EVENT</th><th>ACTOR</th><th>SCOPE</th><th>CATEGORY</th><th>TIME</th><th>RESULT</th></tr></thead><tbody>${events.map(a=>`<tr><td><div class="client-table-avatar"><div class="client-logo">${a[0]}</div><div><strong>${a[1]}</strong><small>${a[6]}</small></div></div></td><td>${a[2]}</td><td>${a[3]}</td><td>${a[4]}</td><td>${a[5]}</td><td><span class="status ${a[7]}">${a[6]}</span></td></tr>`).join('')}</tbody></table></div></section>`}
function mspTeam(){return head('MSP ADMINISTRATION','MSP administrators','Manage internal operator access, roles, client scope, and privileged permissions.','Invite administrator')+`<div class="admin-banner"><strong>? Highest privilege area</strong><span>Only MSP owners can grant integration or cross-client administrative access.</span></div><div class="grid stats">${stat('Administrators','8','2 platform owners','?')}${stat('Technicians','24','Role-scoped access','?')}${stat('Client managers','6','Assigned portfolios','?')}${stat('MFA coverage','100%','Phishing-resistant required','?')}</div><section class="card"><div class="card-head"><div><h2>Internal portal access</h2><p>Northstar personnel with management permissions</p></div><button class="btn secondary">Review permissions</button></div><div class="list">${[['MR','Morgan Reed','Platform owner - All clients'],['MJ','Maya Johnson','Account manager - 8 clients'],['CH','Chris Hall','Service manager - All clients'],['RL','Ryan Lee','Lead technician - 12 clients'],['SB','Sam Brooks','Billing administrator - All clients']].map(p=>row(p[0],p[1],p[2],'<span class="status healthy">Active</span><button class="btn text">Manage</button>')).join('')}</div></section>`}
