function dataMapping(){const template='Incoming {{call.direction}} call from {{contact.name}} at {{company.name}} ({{call.caller_number}}).';const preview='Incoming Inbound call from Maria Jensen at Simi Valley Dental Group ((805) 555-0147).';return head('DATA MAPPING','Data placeholders','Reusable fields for notifications, webhooks, and caller-pop templates.','Add field')+`<div class="ops-placeholder-layout"><section class="card ops-table"><div class="toolbar"><label class="ops-search"><span>?</span><input id="fieldSearch" placeholder="Search fields"></label><span>8 fields</span></div><div class="ops-field-list" id="fieldList">${mappingFields.map(f=>`<button data-copy="${f[0]}" data-field-text="${f.join(' ').toLowerCase()}"><span class="ops-field-group">${f[1]}</span><span><code>${f[0]}</code><small>${f[2]}</small></span><span>${f[3]}</span><b>Copy</b></button>`).join('')}</div></section><aside class="card ops-template"><span class="ops-kicker">LIVE PREVIEW</span><h2>Template tester</h2><p>Use placeholders in a message and preview the resolved output.</p><textarea id="templateInput">${template}</textarea><div class="ops-preview"><span>RESOLVED OUTPUT</span><p id="templatePreview">${preview}</p></div><button class="btn secondary" data-copy="${template}">Copy template</button></aside></div>`}
