function integrations(){return head('INTERNAL MSP ADMINISTRATION','Integration control center.','Vendor connections, synchronization, permissions, and client-visible data controls.','Add integration')+`<div class="admin-banner"><strong>? Internal MSP administrators only</strong><span>End users and client administrators cannot access this page or its APIs. Credentials are stored server-side.</span></div><div class="grid stats">${stat('Connected systems','5','All operational','?')}${stat('Sync failures','0','Last 24 hours','?')}${stat('Credential health','Current','Rotation due Oct 1','?')}${stat('Audit events','18','Today','?')}</div><section class="card"><div class="card-head"><div><h2>Managed integrations</h2><p>Server-side connections and client visibility</p></div><span class="status healthy">Operational</span></div><div class="list">${[['CW','ConnectWise PSA','Companies, tickets, agreements, invoices'],['SC','ScreenConnect','Devices and consent-based sessions'],['H','Hudu','Published knowledge and approved credentials'],['BD','Bitdefender GravityZone','Endpoints, incidents, risk, encryption'],['M365','Microsoft 365','Identity, users, licenses, service health']].map(i=>row(i[0],i[1],i[2],'<span class="status healthy">Connected</span><button class="btn text" data-action="configure">Configure</button>')).join('')}</div></section>`}
