function allowedViewsFor(role,user){const baseline=access[role]||new Set();if(role==='msp'||!Array.isArray(user?.entitlements))return new Set(baseline);const entitled=new Set(user.entitlements);return new Set([...baseline].filter(view=>entitled.has(view)))}
function buildNav(){const el=document.getElementById('navigation');let html='';let open=false;for(const item of nav[state.role]){if(item.length===1){if(open)html+='</div></div></section>';const key=`${state.role}:${item[0].toLowerCase().replace(/[^a-z0-9]+/g,'-')}`;const collapsed=Boolean(state.collapsed[key]);html+=`<section class="nav-section ${collapsed?'is-collapsed':''}" data-section="${key}"><button class="nav-section-toggle" data-nav-section="${key}" aria-expanded="${!collapsed}"><span>${item[0]}</span><b>?</b></button><div class="nav-section-body"><div class="nav-section-inner">`;open=true}else if(state.allowedViews.has(item[0])){html+=`<button class="nav-button ${state.view===item[0]?'active':''}" data-view="${item[0]}"><span>${item[1]}</span>${item[2]}${item[3]?`<em>${item[3]}</em>`:''}</button>`}}if(open)html+='</div></div></section>';el.innerHTML=html}
function backendCollection(records,type){return(records||[]).filter(r=>r.type===type).map(r=>{const p=r.payload||{};if(type==='ticket')return[p.ticketId||r.sourceId||r.id,r.title,p.updatedBy||`${r.sourceSystem||'Portal'} - ${formatTimeAgo(r.updatedAt||r.createdAt)}`,p.statusLabel||r.status,r.status==='resolved'?'resolved':r.priority==='critical'?'critical':'pending',r.priority||'Normal',r.id];if(type==='document')return[r.title,p.file||'Portal record',p.updated||formatTimeAgo(r.updatedAt||r.createdAt),p.category||'General',r.id];if(type==='asset')return[p.category||r.title,Number(p.total)||0,Number(p.healthy)||0,p.summary||r.status,r.priority==='critical'?'critical':r.status==='active'?'healthy':r.status];if(type==='invoice')return[p.invoice||r.title,p.date||'',p.amount||'$0',p.statusLabel||r.status,r.status,r.id];if(type==='renewal')return[r.title,p.date||'Pending',p.value||'$0 ARR',p.note||r.status,r.status];if(type==='person')return[p.initials||initials(r.title),r.title,p.email||'',p.role||'Member',p.department||'',p.phone||'',r.id];return[r.title,r.status,r.priority]})}
function backendPeopleCollection(people){const labels={client_user:'Member',client_admin:'Company administrator',client_owner:'Company owner'};return(people||[]).map(person=>[initials(person.name),person.name,person.email,labels[person.role]||person.role,person.department||'Not set',person.phone||'Not set',person.id,person.membershipStatus||person.status])}
async function hydrateBackendProfile(){if(!state.session?.source||!portalApi.profile)return;try{const payload=await portalApi.profile();if(payload?.profile){uiState.profiles={...(uiState.profiles||{}),[state.role]:Object.fromEntries(Object.entries(payload.profile).filter(([,value])=>typeof value==='string').map(([key,value])=>[key,escapeHtml(value)]))};saveJson('northstar-ui-state',uiState);applyProfileChrome()}}catch(error){console.warn('Profile sync skipped',error.message)}finally{if(state.role==='msp'&&!state.companyId){const scope=state.session?.scope;uiState.activeCompany={...(uiState.activeCompany||{}),msp:{initials:String(scope?.clientCount||portfolioClientCount()),name:scope?.label||'All managed clients',plan:`${scope?.clientCount||portfolioClientCount()} client portfolio`}};saveJson('northstar-ui-state',uiState);updateCompanyChrome(uiState.activeCompany.msp)}void hydrateBackendCompanyMaster()}}
async function hydrateBackendCompanyMaster(renderCurrent=true){if(!state.session?.source||!state.companyId||!portalApi.company)return;try{const payload=await portalApi.company(state.companyId);const company=payload?.company;if(!company)return;const current=activeClientData();const oldName=current.name;const profile=company.profile||{};current.name=company.name;current.initials=company.initials||initials(company.name);current.plan=company.planName||current.plan;current.address=profile.address||current.address;current.location=profile.primaryLocation||current.location||current.address;current.phone=profile.phone||current.phone;current.website=profile.website||company.primaryDomain||current.website;current.industry=profile.industry||current.industry;current.employees=Number(profile.employees)||current.employees;current.agreement.users=current.employees;if(oldName!==current.name){delete clientRecords[oldName];clientRecords[current.name]=current}storeApi.renameStoreClient?.(oldName,{id:company.id,name:current.name,initials:current.initials,plan:current.plan,status:company.status});uiState.activeCompany={...(uiState.activeCompany||{}),[state.role]:{id:company.id,name:current.name,initials:current.initials,plan:current.plan}};saveJson('northstar-ui-state',uiState);updateCompanyChrome(uiState.activeCompany[state.role]);if(renderCurrent&&['overview','company','team','billing','documents','restrictions'].includes(state.view))render(state.view)}catch(error){console.warn('Company master sync skipped',error.message)}}
async function hydrateBackendCompanyRecords(){if(!state.session?.source||!state.companyId||!portalApi.listRecords)return;try{const c=activeClientData();const[recordsPayload,approvalsPayload,peoplePayload,settingsPayload,auditPayload]=await Promise.all([portalApi.listRecords(state.companyId),portalApi.listApprovals?.(state.companyId,'pending'),state.role!=='user'?portalApi.listPeople?.(state.companyId):null,portalApi.listSettings?.(state.companyId),state.role==='msp'?portalApi.listAudit?.(state.companyId,100):null]);const records=recordsPayload?.records||[];const people=peoplePayload?.people?.length?backendPeopleCollection(peoplePayload.people):backendCollection(records,'person');storeApi.setStoreRecords?.(c.name,{tickets:backendCollection(records,'ticket'),documents:backendCollection(records,'document'),assets:backendCollection(records,'asset'),invoices:backendCollection(records,'invoice'),renewals:backendCollection(records,'renewal'),people});storeState.approvals=(storeState.approvals||[]).filter(a=>a.scope!==c.name);(approvalsPayload?.approvals||[]).forEach(a=>storeState.approvals.unshift({id:a.id,kind:a.kind,scope:c.name,details:a.title,status:a.status,createdAt:a.createdAt,actor:'Backend'}));for(const setting of settingsPayload?.settings||[]){const value=setting.value;if(setting.scope==='company'&&value&&typeof value==='object'&&value.view&&value.label)uiState.toggles[`${state.role}:${value.view}:${value.label}`]=Boolean(value.enabled)}if(auditPayload?.events){storeState.audit=(storeState.audit||[]).filter(a=>a.scope!==c.name);auditPayload.events.forEach(event=>storeState.audit.push({id:event.id,type:event.action,scope:c.name,details:event.reasonCode||event.resourceType,actor:event.actorEmail||event.actorRole||'Portal',createdAt:event.createdAt,outcome:event.outcome}))}saveJson('northstar-ui-state',uiState);storeApi.savePortalStore?.();if(['overview','support','documents','billing','team','restrictions','audit'].includes(state.view))render(state.view)}catch(error){console.warn('Backend sync skipped',error.message)}}
function persistBackendRecord(type,title,payload={},extra={}){if(!state.session?.source||!state.companyId||!portalApi.createRecord)return null;const promise=portalApi.createRecord(state.companyId,{id:extra.id,type,title,payload,status:extra.status||'active',priority:extra.priority||'normal',sourceSystem:'portal',sourceId:extra.sourceId,visibleToClient:extra.visibleToClient!==false});void promise.catch(error=>console.warn('Backend record save skipped',error.message));return promise}
function persistBackendApproval(kind,title,payload={}){if(!state.session?.source||!state.companyId||!portalApi.createApproval)return;void portalApi.createApproval(state.companyId,{kind,title,payload}).catch(error=>console.warn('Backend approval save skipped',error.message))}
function backendTicketRecordId(ticket){return ticket?.[6]||`ticket-${String(ticket?.[0]||'ticket').toLowerCase().replace(/[^a-z0-9]+/g,'-')}`}
function persistTicketState(ticket,action,note=''){if(!ticket||!state.session?.source||!state.companyId)return;const recordId=backendTicketRecordId(ticket);ticket[6]=recordId;const payload={ticketId:ticket[0],updatedBy:`${actionActor()} - Just now`,statusLabel:ticket[3],lastAction:action,lastNote:note,history:[{action,note,actor:actionActor(),at:new Date().toISOString(),status:ticket[3]}]};const patch={title:plain(ticket[1]),status:ticket[4]==='resolved'?'resolved':'active',priority:String(ticket[5]||'Normal').toLowerCase(),sourceSystem:'portal',sourceId:ticket[0],payload};if(ticket[6]&&portalApi.updateRecord)void portalApi.updateRecord(state.companyId,recordId,patch).catch(()=>persistBackendRecord('ticket',ticket[1],payload,{id:recordId,status:patch.status,priority:patch.priority,sourceId:ticket[0]}));else persistBackendRecord('ticket',ticket[1],payload,{id:recordId,status:patch.status,priority:patch.priority,sourceId:ticket[0]})}
function backendInvoiceRecordId(invoice){return invoice?.[5]||`invoice-${String(invoice?.[0]||'invoice').toLowerCase().replace(/[^a-z0-9]+/g,'-')}`}
function persistInvoiceState(invoice,action='payment-submitted',payment={}){if(!invoice||!state.session?.source||!state.companyId)return;const recordId=backendInvoiceRecordId(invoice);invoice[5]=recordId;const payload={invoice:invoice[0],date:invoice[1],amount:invoice[2],statusLabel:invoice[3],lastAction:action,payment:{...payment,actor:actionActor(),at:new Date().toISOString()}};const patch={title:invoice[0],status:invoice[4]==='paid'?'paid':'active',priority:invoice[4]==='critical'?'critical':'normal',sourceSystem:'portal',sourceId:invoice[0],payload};if(portalApi.updateRecord)void portalApi.updateRecord(state.companyId,recordId,patch).catch(()=>persistBackendRecord('invoice',invoice[0],payload,{id:recordId,status:patch.status,priority:patch.priority,sourceId:invoice[0]}));else persistBackendRecord('invoice',invoice[0],payload,{id:recordId,status:patch.status,priority:patch.priority,sourceId:invoice[0]})}
function render(view='overview'){if(!views[view]||!state.allowedViews.has(view)){toast('Your role does not have access to that area');const preferred=state.role==='msp'?'management':'overview';view=state.allowedViews.has(preferred)?preferred:[...state.allowedViews][0]}if(!view||!views[view])throw new Error('No portal modules are enabled for this account.');state.view=view;buildNav();document.getElementById('content').innerHTML=organizationBar(view)+portalGovernanceBanner(view)+views[view]();applySavedUiState();applyPortalChrome();document.getElementById('sidebar').classList.remove('open');document.getElementById('overlay').classList.remove('show');scrollTo({top:0,behavior:'smooth'})}
function login(role,user=null){if(!['user','admin','msp'].includes(role))throw new Error('Invalid portal role.');if(user?.source==='entra'&&role!=='msp'&&!user.tenant)throw new Error('An active company assignment is required.');state.role=role;state.user=user;state.session=user;state.companyId=user?.companyId||null;state.entitlements=new Set(user?.entitlements||[]);state.allowedViews=allowedViewsFor(role,user);state.view=role==='msp'?'management':'overview';document.documentElement.dataset.portalRole=role;document.getElementById('loginScreen').classList.add('hidden');document.getElementById('portal').hidden=false;const person=user||currentProfile();const roleLabels={user:'End user',admin:'Client administrator',msp:user?.platformRole==='msp_owner'?'MSP platform owner':user?.platformRole==='msp_operator'?'MSP operator':'Internal MSP administrator'};document.getElementById('profileRole').textContent=roleLabels[role];const p=currentProfile();document.getElementById('profileName').textContent=p.name||person.name;document.getElementById('avatar').textContent=initials(p.name||person.name);const tenant=user?.tenant||user?.company;const scope=user?.scope;if(!uiState.activeCompany?.[role]){const fallback=role==='msp'?{initials:String(scope?.clientCount||portfolioClientCount()),name:scope?.label||'All managed clients',plan:`${scope?.clientCount||portfolioClientCount()} client portfolio`}:companyOptions()[0];uiState.activeCompany={...(uiState.activeCompany||{}),[role]:fallback};saveJson('northstar-ui-state',uiState)}if(role!=='msp'&&tenant){uiState.activeCompany={...(uiState.activeCompany||{}),[role]:{id:tenant.id,initials:tenant.initials||'AC',name:tenant.name||'Acme & Co.',plan:tenant.planName||'Managed Complete'}};saveJson('northstar-ui-state',uiState)}if(role==='msp'){const clientsItem=nav.msp.find(item=>item[0]==='clients');if(clientsItem)clientsItem[3]=String(scope?.clientCount||portfolioClientCount())}const brandLogo=document.querySelector('.sidebar .logo');brandLogo.classList.toggle('ops-brand-mark',role==='msp');if(role==='msp')brandLogo.innerHTML='<i></i><i></i><i></i>';else brandLogo.textContent='N';updateCompanyChrome(uiState.activeCompany?.[role]||companyOptions()[0]);if(!user&&previewMode)sessionStorage.setItem('northstar-role',role);render(state.view);void hydrateBackendProfile();void hydrateBackendCompanyRecords()}
function toast(msg){const t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),2400)}
