function nextTicketId(){const nums=activeClientData().tickets.map(t=>Number(String(t[0]).replace(/\D/g,''))).filter(Number.isFinite);return`NS-${String(Math.max(2841,...nums)+1).padStart(4,'0')}`}
function addTicket(subject,type='Support request',impact='Normal'){const c=activeClientData();const safeSubject=escapeHtml(subject||type);const priority=/critical|security|high/i.test(`${type} ${impact}`)?'High':'Normal';const id=nextTicketId();const person=state.user?.name||document.getElementById('profileName')?.textContent||'Portal user';const item=[id,safeSubject,`${escapeHtml(person)} - Just now`,'New','pending',priority];item[6]=backendTicketRecordId(item);c.tickets.unshift(item);storeApi.addStoreRecord?.(c.name,'tickets',item);storeApi.recordStoreAudit?.('ticket-created',c.name,`${id}: ${safeSubject}`,person);persistBackendRecord('ticket',safeSubject,{ticketId:id,updatedBy:item[2],statusLabel:item[3],requestType:type,impact,createdBy:person},{id:item[6],status:'active',priority:priority.toLowerCase(),sourceId:id});if(c.name==='Acme & Co.'){demoState.tickets=demoState.tickets||[];demoState.tickets.unshift(item);saveDemo()}return id}
function actionLabel(trigger){return plain(trigger?.dataset.actionLabel||trigger?.textContent||'Action').replace(/^[++]\s*/,'').trim()}
function actionField(field){const value=escapeHtml(field.value||'');const required=field.required===false?'':' required';const placeholder=field.placeholder?` placeholder="${escapeHtml(field.placeholder)}"`:'';if(field.type==='textarea')return`<label>${escapeHtml(field.label)}<textarea name="${field.name}" rows="${field.rows||4}"${placeholder}${required}>${value}</textarea></label>`;if(field.type==='select')return`<label>${escapeHtml(field.label)}<select name="${field.name}"${required}>${(field.options||[]).map(o=>`<option${o===field.value?' selected':''}>${escapeHtml(o)}</option>`).join('')}</select></label>`;return`<label>${escapeHtml(field.label)}<input name="${field.name}" type="${field.type||'text'}" value="${value}"${placeholder}${required}></label>`}
function openActionModal({kicker='PORTAL ACTION',title='Action',body='',type='generic',fields=[],submit='Save',html=''}){const content=document.getElementById('actionModalContent');const done=html.includes('modal-actions')?'':'<div class="modal-actions"><button type="button" class="btn primary" data-action="close">Done</button></div>';const form=fields.length?`<form id="actionForm" data-form-type="${type}" class="action-grid">${fields.map(actionField).join('')}<div class="modal-actions"><button type="button" class="btn secondary" data-action="close">Cancel</button><button class="btn primary" type="submit">${escapeHtml(submit)}</button></div></form>`:`<div>${html}</div>${done}`;content.innerHTML=`<div class="modal-head"><div><span class="eyebrow">${escapeHtml(kicker)}</span><h2 id="actionTitle">${escapeHtml(title)}</h2></div><button data-action="close" aria-label="Close">-</button></div>${body?`<p class="modal-copy">${body}</p>`:''}${form}`;document.getElementById('actionModal').hidden=false;setTimeout(()=>content.querySelector('input,select,textarea,button')?.focus(),20)}
function openPayment(){const c=activeClientData();const due=c.invoices.find(i=>i[4]!=='paid')||c.invoices[0];openActionModal({kicker:'PAYMENT',title:'Schedule payment',body:`Confirm the ${c.name} invoice and payment method. This prototype updates the invoice status locally.`,type:'payment',submit:'Submit payment',fields:[{name:'invoice',label:'Invoice',value:due[0]},{name:'amount',label:'Amount',value:due[2]},{name:'method',label:'Payment method',type:'select',options:[...c.payments.map(p=>p[0]),'New payment method']},{name:'date',label:'Payment date',type:'select',options:['Today','Due date','Next business day']}]})}
