function openCompanyChange(){const c=activeClientData();if(state.role==='user'){openActionModal({kicker:'COMPANY CHANGE REQUEST',title:`Request update for ${c.name}`,body:'End users submit proposed changes for Client Admin/MSP review. This creates a shared support record.',type:'company-change-request',submit:'Submit request',fields:[{name:'field',label:'Field to update',type:'select',options:['Main phone','Website','Primary location','Department/contact','Other']},{name:'value',label:'Requested value',placeholder:'Enter the corrected value'},{name:'reason',label:'Reason',type:'textarea',required:false,placeholder:'Why should this be updated?'}]});return}openActionModal({kicker:'SHARED COMPANY RECORD',title:`Update ${c.name}`,body:'Changes update the shared company object used by MSP Admin, Client Admin, and End User portals.',type:'company-change',submit:'Apply shared update',fields:[{name:'name',label:'Company name',value:c.name},{name:'address',label:'Primary location',value:c.address},{name:'phone',label:'Main phone',type:'tel',value:c.phone},{name:'website',label:'Website',value:c.website},{name:'industry',label:'Industry',value:c.industry},{name:'employees',label:'Employees',type:'number',value:String(c.employees)}]})}
