function openNotifications(){const items=[['Security digest ready','Bitdefender and access review summary is ready.','2 min ago'],['Invoice due soon','INV-2026-0711 is due July 15.','Today'],['Remote session completed','ScreenConnect session closed successfully.','Yesterday']];openActionModal({kicker:'NOTIFICATIONS',title:'Notification center',body:'Recent client and MSP portal events.',html:`<div class="list">${items.map(n=>row('?',n[0],n[1],`<strong>${n[2]}</strong>`)).join('')}</div>`})}
function companyOptions(){if(state.role==='msp'){const backend=state.session?.availableCompanies||[];if(backend.length)return backend.map(c=>({id:c.id,initials:c.initials||initials(c.name),name:c.name,plan:c.planName||'Managed Services'}));return clientPortfolio.map(c=>({initials:c[0],name:c[1],plan:`${c[2].split(' - ')[0]} - ${c[5]} MRR`}))}const c=clientRecords['Acme & Co.'];return[{id:state.companyId,initials:c.initials,name:c.name,plan:c.plan},{id:state.companyId,initials:c.initials,name:`${c.name} - Billing`,plan:'Billing administration'}]}
