function openCompanySwitcher(){const options=companyOptions();openActionModal({kicker:'COMPANY SCOPE',title:'Switch company',body:state.role==='msp'?'Select the client context for management work.':'Select the company scope assigned to your account.',html:`<div class="choice-list">${options.map((c,i)=>`<button data-action="select-company" data-company-index="${i}"><span class="company-avatar">${escapeHtml(c.initials)}</span><span><b>${escapeHtml(c.name)}</b><small>${escapeHtml(c.plan)}</small></span><strong>Open</strong></button>`).join('')}</div>`})}
function selectCompany(trigger){const company=companyOptions()[Number(trigger.dataset.companyIndex)];if(!company)return;const record=clientRecords[company.name];state.companyId=company.id||state.companyId;uiState.activeCompany={...(uiState.activeCompany||{}),[state.role]:record?{id:state.companyId,initials:record.initials,name:record.name,plan:company.plan||record.plan}:company};if(record)syncCompanyAcrossPortals(uiState.activeCompany[state.role]);saveJson('northstar-ui-state',uiState);updateCompanyChrome(uiState.activeCompany[state.role]);closeAction();toast(`${uiState.activeCompany[state.role].name} selected across all portals`);render(state.view);void hydrateBackendCompanyMaster(false);void hydrateBackendCompanyRecords()}
function downloadText(filename,text){const blob=new Blob([text],{type:'text/plain'});const url=URL.createObjectURL(blob);const link=document.createElement('a');link.href=url;link.download=filename;document.body.appendChild(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(url),500)}
function exportVisibleData(){const rows=[];const table=document.querySelector('#content table');if(table){table.querySelectorAll('tr:not([hidden])').forEach(tr=>rows.push([...tr.children].map(cell=>plain(cell.innerHTML).trim())))}else document.querySelectorAll('#content .list-row:not([hidden])').forEach(rowEl=>rows.push([plain(rowEl.querySelector('.row-copy strong')?.innerHTML),plain(rowEl.querySelector('.row-copy span')?.innerHTML),plain(rowEl.querySelector('.row-meta')?.innerHTML)]));if(!rows.length){toast('Nothing visible to export');return}const csv=rows.map(row=>row.map(cell=>`"${String(cell||'').replace(/"/g,'""')}"`).join(',')).join('\n');downloadText(`${state.view||'portal'}-export.csv`,csv);toast('Export downloaded')}
