function handleApprovalAction(action,trigger){if(!action.startsWith('approval-'))return false;const decision=action.replace('approval-','').replace('approve','approved').replace('deny','denied').replace('cancel','cancelled');const item=(storeState.approvals||[]).find(entry=>entry.id===trigger.dataset.approvalId);if(!item)return true;approvalDecisionContext={id:item.id,decision};openActionModal({kicker:'APPROVAL WORKFLOW',title:item.details||'Approval request',body:`Record a ${decision} decision for ${activeClientData().name}. The result and reason will be written to the shared audit trail.`,type:'approval-decision',submit:decision==='cancelled'?'Withdraw request':decision==='approved'?'Approve request':'Deny request',fields:[{name:'decision',label:'Decision',type:'select',options:[decision]},{name:'reason',label:'Decision reason',type:'textarea',required:decision!=='cancelled',placeholder:decision==='cancelled'?'Optional withdrawal note':'Required business reason for the audit record'}]});return true}
