async function saveProfileForm(form){const data=Object.fromEntries(new FormData(form));try{const saved=state.session?.source&&portalApi.updateProfile?await portalApi.updateProfile(data):null;const values=saved?.profile||data;uiState.profiles={...(uiState.profiles||{}),[state.role]:Object.fromEntries(Object.entries(values).filter(([,value])=>typeof value==='string').map(([key,value])=>[key,escapeHtml(value)]))};saveJson('northstar-ui-state',uiState);applyProfileChrome();closeAction();toast('Profile saved')}catch(error){toast(error.message||'Profile could not be saved')}}
