async function saveApprovalDecisionForm(form){if(!approvalDecisionContext)return;const data=Object.fromEntries(new FormData(form));const decision=approvalDecisionContext.decision;try{const saved=state.session?.source&&portalApi.decideApproval?await portalApi.decideApproval(state.companyId,approvalDecisionContext.id,{decision,reason:data.reason||''}):null;const item=(storeState.approvals||[]).find(entry=>entry.id===approvalDecisionContext.id);if(item)item.status=saved?.approval?.status||decision;workflowRecord(`approval-${decision}`,item?.details||approvalDecisionContext.id,data.reason||'Request withdrawn');storeApi.savePortalStore?.();approvalDecisionContext=null;closeAction();toast(`Request ${decision}`);render(state.view)}catch(error){toast(error.message||'Approval decision could not be saved')}}
async function saveSpecialActionForm(form){const data=Object.fromEntries(new FormData(form));const type=form.dataset.formType;if(type==='integration'){if(!state.session?.source||!portalApi.saveIntegration)throw new Error('The connected portal API is required to save an integration.');const provider=String(data.system||'').toLowerCase().replace(/[^a-z0-9]+/g,'');const saved=await portalApi.saveIntegration({provider,name:data.system,scope:data.scope,syncInterval:data.sync});closeAction();toast(`${saved.integration.name} configuration saved`);render('integrations');return}if(type==='api-key'){if(!state.session?.source||!portalApi.createApiKey)throw new Error('The connected portal API is required to create an API key.');const expiryDays=Number(String(data.expires||'90').match(/\d+/)?.[0])||90;const saved=await portalApi.createApiKey({name:data.name,scope:data.scope,expiryDays});openActionModal({kicker:'API KEY CREATED',title:saved.apiKey.name,body:'Copy this key now. It is shown only once and only its hash is stored by the portal.',html:`<div class="secret-box">${escapeHtml(saved.apiKey.secret)}</div><div class="modal-actions"><button class="btn secondary" data-copy="${escapeHtml(saved.apiKey.secret)}">Copy key</button><button class="btn primary" data-action="close">Close</button></div>`});return}if(type==='remote'){const id=addTicket(`Remote support request: ${data.device}`,'Remote support',data.reason||'Normal');if(state.session?.source&&portalApi.createApproval)await portalApi.createApproval(state.companyId,{kind:'remote_support',title:`Remote support consent: ${data.device}`,payload:{device:data.device,reason:data.reason,ticket:id}});workflowRecord('remote-consent',data.device,`Ticket ${id}`);closeAction();toast(`Remote support request ${id} submitted for approval`);render('support');return}if(['create-record','field','policy','rotate-key'].includes(type)){const label=data.name||currentModalTitle()||'Portal follow-up';const id=addTicket(`${pageLabel[state.view]||'Portal'}: ${label}`,'Portal follow-up',data.notes||'Normal');if(state.session?.source&&portalApi.createApproval)await portalApi.createApproval(state.companyId,{kind:'portal_follow_up',title:`${pageLabel[state.view]||'Portal'} follow-up: ${label}`,payload:{owner:data.owner||'',notes:data.notes||'',ticket:id}});workflowRecord('portal-follow-up',label,`Ticket ${id}`);closeAction();toast(`Follow-up ${id} created`);render('support');return}throw new Error('Unsupported portal action.')}
